import java.io.*;
import org.owasp.html.PolicyFactory;
import org.owasp.html.Sanitizers;

public class XSSSecureCode {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userName = reader.readLine();

        // Create a policy to sanitize user input
        PolicyFactory policy = Sanitizers.FORMATTING.and(Sanitizers.BLOCKS);

        // Sanitize user input before displaying it
        String sanitizedUserName = policy.sanitize(userName);

        System.out.println("Welcome, " + sanitizedUserName + "!");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
